class Solution:
    def largestPalindrome(self, n: int, k: int) -> str:
        if n == 1:
            return '9' if k == 4 else '8'
        max_num = int('9' * n)
        for i in range(max_num, int('9' * (n - 1)), -1):
            num = i
            rev_num = 0
            while num > 0:
                rev_num = rev_num * 10 + num % 10
                num //= 10
            if str(rev_num) + str(i) % k == 0 and str(rev_num) + str(i) == str(rev_num) + str(i)[::-1]:
                return str(rev_num) + str(i)
        return ''
